import{_ as e,o as t,c as i,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F07: 存貨週轉效率同業對比 - 財務審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3680_家登/20260509/F07_存貨週轉效率同業對比.md","filePath":"審計報告庫/財務審計/3680_家登/20260509/F07_存貨週轉效率同業對比.md"}'),n={name:"審計報告庫/財務審計/3680_家登/20260509/F07_存貨週轉效率同業對比.md"};function o(l,a,s,h,d,c){return t(),i("div",null,[...a[0]||(a[0]=[r('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f07-存貨週轉效率同業對比-財務審計專家報告" tabindex="-1">F07: 存貨週轉效率同業對比 - 財務審計專家報告 <a class="header-anchor" href="#f07-存貨週轉效率同業對比-財務審計專家報告" aria-label="Permalink to &quot;F07: 存貨週轉效率同業對比 - 財務審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>存貨週轉天數與同業對比之競爭優勢判斷，整體營運週期是否處於擴張狀態。</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：DIO 152 天略高於 Entegris 127 天但優於台系同業均值 200-230 天。2025 年存貨效率大幅改善，營運週期收縮中。</li><li><strong>風險評級</strong>：低-中</li><li><strong>數據時效</strong>：2025 Q4</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>家登 DIO 152 天 vs Entegris 127 天（差 20%），但優於台系同業均值 190-210 天（帆宣 268 天、京鼎 225 天）。現金循環 483 天較 2023 年峰值 828 天收縮 345 天改善顯著。DSO 82 天待優化，DPO 186 天遠低同業 250-350 天，對供應商議價權弱勢為營運週期結構瓶頸。2025 年存貨首降 2.9% 配合 2nm 量產，去化動能好轉。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="一、存貨週轉天數同業對比" tabindex="-1">一、存貨週轉天數同業對比 <a class="header-anchor" href="#一、存貨週轉天數同業對比" aria-label="Permalink to &quot;一、存貨週轉天數同業對比&quot;">​</a></h3><p>家登 DIO 152 天高於 Entegris 127 天（+19.7%），但優於台系多數同業 200-230 天。Entegris 優勢來自全球多點布局（美/星/台）降低跨國運輸庫存，家登以台灣為主，日本新廠 2026 年完工後可望改善。</p><h3 id="二、營運週期結構" tabindex="-1">二、營運週期結構 <a class="header-anchor" href="#二、營運週期結構" aria-label="Permalink to &quot;二、營運週期結構&quot;">​</a></h3><p>現金循環 483 天（DIO 587 + DSO 82 - DPO 186），較 2023 年高點 828 天收縮 345 天。結構呈現兩極化——DIO 中位、DSO 偏高（82 天）、DPO 極短（186 天 vs 同業 250-350 天）。DPO 短反映對上游議價權弱勢，為營運週期的結構性瓶頸。</p><h3 id="三、庫存去化動能" tabindex="-1">三、庫存去化動能 <a class="header-anchor" href="#三、庫存去化動能" aria-label="Permalink to &quot;三、庫存去化動能&quot;">​</a></h3><p>2025 年存貨首降 2.9%（4 年來首次），配合 2nm 量產時程驗證備貨策略正確。但季度 COGS 波動劇烈（Q4 營收為 Q1 1.33 倍）使 DIO 計算口徑差異大。</p><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析（Skepticism Mandate） <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析（Skepticism Mandate）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><strong>Entegris DIO 127 天優於家登 152 天（差 20%）</strong>，若 Entegris 在 High-NA 世代取得訂單，獨佔地位面臨<strong>競爭</strong>壓力。</li><li><strong>DPO 186 天為同業最低</strong>，比同業早付 100-200 天，隱含供應商量少無議價權，漲價將承壓。</li><li><strong>483 天現金循環需 16 個月回收資金</strong>，FCF 為負下營運資金佔用為折價因子。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><strong>DIO 從 1,048 天持續改善</strong>，2025 年庫存反轉下降，管理效率已見成效。</li><li><strong>台系同業中名列前茅</strong>（均值 200+ 天），在供應鏈具效率優勢。</li><li><strong>日本新廠在地供貨</strong>，預估 DIO 再降 20-30 天至 120-130 天。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>台系前段但全球與 Entegris 有差距。現金循環偏長為結構問題，日本新廠營運後可望改善。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>計算工具：財務分析工具.py (inventory_check 3680 2022 2025)、(inventory_check 6196,3413,3583,3131 2022 2025)</li><li>原始數據：FinMind TaiwanStockBalanceSheet + TaiwanStockFinancialStatements</li><li>同業對比：web_search 同業存貨週轉率數據（Q4 2025）及 WantGoo / StatementDog 營運效率頁面</li><li>查詢參數：stock_id=3680, start=2022-01-01, end=2025-12-31</li><li>數據查詢日期：2026-05-09</li></ul>',24)])])}const m=e(n,[["render",o]]);export{u as __pageData,m as default};
